#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding mental-health-assessment (15 tables)..."

cargo loco generate scaffold patient \
    first_name:string! \
    last_name:string! \
    date_of_birth:date! \
    nhs_number:string^ \
    sex:string! \
    weight_kg:double \
    height_cm:double \
    bmi:double \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    status:string! \
    --htmx

cargo loco generate scaffold assessment_demographics \
    assessment:references \
    occupation:string! \
    marital_status:string! \
    living_situation:string! \
    ethnicity:string! \
    contact_phone:string! \
    contact_email:string! \
    emergency_contact_name:string! \
    emergency_contact_phone:string! \
    gp_name:string! \
    gp_practice:string! \
    --htmx

cargo loco generate scaffold assessment_phq9_depression_screen \
    assessment:references \
    q1_little_interest:int \
    q2_feeling_down:int \
    q3_sleep_problems:int \
    q4_feeling_tired:int \
    q5_appetite_changes:int \
    q6_feeling_bad_about_self:int \
    q7_trouble_concentrating:int \
    q8_moving_slowly_or_fidgety:int \
    q9_thoughts_of_self_harm:int \
    phq9_total_score:int \
    difficulty_level:string! \
    --htmx

cargo loco generate scaffold assessment_gad7_anxiety_screen \
    assessment:references \
    q1_feeling_nervous:int \
    q2_uncontrollable_worrying:int \
    q3_worrying_too_much:int \
    q4_trouble_relaxing:int \
    q5_restlessness:int \
    q6_easily_annoyed:int \
    q7_feeling_afraid:int \
    gad7_total_score:int \
    difficulty_level:string! \
    --htmx

cargo loco generate scaffold assessment_mood_and_affect \
    assessment:references \
    current_mood:string! \
    mood_stability:string! \
    affect:string! \
    sleep_quality:string! \
    sleep_hours_per_night:double \
    appetite:string! \
    energy_level:string! \
    motivation_level:string! \
    anhedonia:string! \
    irritability:string! \
    psychomotor_changes:string! \
    mood_notes:text! \
    --htmx

cargo loco generate scaffold assessment_risk_assessment \
    assessment:references \
    suicidal_ideation:string! \
    suicidal_ideation_frequency:string! \
    suicidal_plan:string! \
    suicidal_intent:string! \
    previous_suicide_attempts:string! \
    previous_attempt_count:int \
    previous_attempt_details:text! \
    self_harm:string! \
    self_harm_type:text! \
    harm_to_others:string! \
    harm_to_others_details:text! \
    access_to_means:string! \
    access_to_means_details:text! \
    protective_factors:text! \
    overall_risk_level:string! \
    safety_plan_in_place:string! \
    risk_notes:text! \
    --htmx

cargo loco generate scaffold assessment_substance_use \
    assessment:references \
    alcohol_use:string! \
    alcohol_units_per_week:int \
    alcohol_concern:string! \
    tobacco_use:string! \
    tobacco_per_day:int \
    cannabis_use:string! \
    recreational_drug_use:string! \
    recreational_drug_details:text! \
    prescription_misuse:string! \
    prescription_misuse_details:text! \
    caffeine_intake:string! \
    previous_substance_treatment:string! \
    previous_substance_treatment_details:text! \
    substance_use_notes:text! \
    --htmx

cargo loco generate scaffold assessment_current_medications \
    assessment:references \
    taking_psychotropic_medication:string! \
    medication_adherence:string! \
    side_effects:string! \
    side_effects_details:text! \
    over_the_counter_medications:text! \
    supplements:text! \
    medication_notes:text! \
    --htmx

cargo loco generate scaffold assessment_current_medication_item \
    current_medications:references \
    medication_name:string! \
    dose:string! \
    frequency:string! \
    prescriber:string! \
    start_date:date \
    medication_class:string! \
    sort_order:int! \
    --htmx

cargo loco generate scaffold assessment_treatment_history \
    assessment:references \
    previous_psychiatric_diagnosis:string! \
    previous_diagnoses:text! \
    previous_therapy:string! \
    therapy_type:string! \
    therapy_details:text! \
    previous_psychiatric_admission:string! \
    admission_count:int \
    admission_details:text! \
    crisis_team_involvement:string! \
    sectioned_under_mental_health_act:string! \
    section_details:text! \
    electroconvulsive_therapy:string! \
    treatment_response:text! \
    treatment_history_notes:text! \
    --htmx

cargo loco generate scaffold assessment_social_and_functional \
    assessment:references \
    employment_status:string! \
    employment_impact:text! \
    social_support:string! \
    social_isolation:string! \
    relationship_difficulties:string! \
    relationship_details:text! \
    financial_difficulties:string! \
    housing_issues:string! \
    housing_details:text! \
    caring_responsibilities:string! \
    caring_details:text! \
    daily_functioning:string! \
    hobbies_and_interests:text! \
    exercise_frequency:string! \
    social_functional_notes:text! \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    phq9_total_score:int! \
    phq9_severity:string! \
    gad7_total_score:int! \
    gad7_severity:string! \
    risk_level:string! \
    graded_at:ts! \
    --htmx

cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    rule_id:string! \
    category:string! \
    description:text! \
    severity_level:string! \
    --htmx

cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:string! \
    category:string! \
    message:text! \
    priority:string! \
    --htmx

echo "Done."
